--- tests/unit/webview/workflow/foundations.test.tsx	
+++ tests/unit/webview/workflow/foundations.test.tsx	
@@ -0,0 +1,81 @@
+import { render, screen } from "@testing-library/react";
+import { describe, expect, it } from "vitest";
+import { Button } from "../../../../ui/src/components/ui/button";
+import {
+	ActionToolbar,
+	EmptyState,
+	MetricRow,
+	PanelSection,
+} from "../../../../ui/src/components/workflow";
+
+describe("workflow foundation components", () => {
+	it("renders panel sections with shared header content and actions", () => {
+		render(
+			<PanelSection
+				actions={<Button size="sm">Refresh</Button>}
+				description="Shared orchestration section shell"
+				title="Overview"
+			>
+				<div>Section body</div>
+			</PanelSection>
+		);
+
+		expect(screen.getByText("Overview")).toBeInTheDocument();
+		expect(
+			screen.getByText("Shared orchestration section shell")
+		).toBeInTheDocument();
+		expect(screen.getByRole("button", { name: "Refresh" })).toBeInTheDocument();
+		expect(screen.getByText("Section body")).toBeInTheDocument();
+	});
+
+	it("renders metric rows with labels, values, and helper copy", () => {
+		render(
+			<MetricRow
+				helper="Updated 2 minutes ago"
+				label="Active provider"
+				value="Devin"
+			/>
+		);
+
+		expect(screen.getByText("Active provider")).toBeInTheDocument();
+		expect(screen.getByText("Devin")).toBeInTheDocument();
+		expect(screen.getByText("Updated 2 minutes ago")).toBeInTheDocument();
+	});
+
+	it("renders empty states with shared actions", () => {
+		render(
+			<EmptyState
+				actions={<Button size="sm">Open Agent Chat</Button>}
+				description="Start a local session or connect a provider."
+				eyebrow="Running agents"
+				title="No sessions yet"
+			/>
+		);
+
+		expect(screen.getByText("Running agents")).toBeInTheDocument();
+		expect(screen.getByText("No sessions yet")).toBeInTheDocument();
+		expect(
+			screen.getByText("Start a local session or connect a provider.")
+		).toBeInTheDocument();
+		expect(
+			screen.getByRole("button", { name: "Open Agent Chat" })
+		).toBeInTheDocument();
+	});
+
+	it("renders toolbars as compact action groups", () => {
+		render(
+			<ActionToolbar aria-label="orchestration actions" density="compact">
+				<Button size="sm">Refresh</Button>
+				<Button size="sm" variant="outline">
+					Open Cloud Agents
+				</Button>
+			</ActionToolbar>
+		);
+
+		expect(screen.getByLabelText("orchestration actions")).toBeInTheDocument();
+		expect(screen.getByRole("button", { name: "Refresh" })).toBeInTheDocument();
+		expect(
+			screen.getByRole("button", { name: "Open Cloud Agents" })
+		).toBeInTheDocument();
+	});
+});

Index: tests/unit/webview/workflow/status-badge.test.tsx
===================================================================
--- tests/unit/webview/workflow/status-badge.test.tsx	
+++ tests/unit/webview/workflow/status-badge.test.tsx	
@@ -0,0 +1,30 @@
+import { render, screen } from "@testing-library/react";
+import { describe, expect, it } from "vitest";
+import {
+	formatWorkflowStatusLabel,
+	getWorkflowStatusTone,
+	StatusBadge,
+} from "../../../../ui/src/components/workflow";
+
+describe("StatusBadge", () => {
+	it("maps representative orchestration and hook statuses to shared tones", () => {
+		expect(getWorkflowStatusTone("running")).toBe("active");
+		expect(getWorkflowStatusTone("waiting-for-input")).toBe("warning");
+		expect(getWorkflowStatusTone("completed")).toBe("success");
+		expect(getWorkflowStatusTone("failed")).toBe("danger");
+		expect(getWorkflowStatusTone("paused")).toBe("warning");
+		expect(getWorkflowStatusTone("unknown-state")).toBe("neutral");
+	});
+
+	it("formats machine status strings into badge labels", () => {
+		expect(formatWorkflowStatusLabel("waiting_for_input")).toBe(
+			"waiting for input"
+		);
+	});
+
+	it("renders the formatted status label by default", () => {
+		render(<StatusBadge status="ended-by-shutdown" />);
+
+		expect(screen.getByText("ended by shutdown")).toBeInTheDocument();
+	});
+});

