 /* Task list checkbox styles for markdown preview */
 .task-list-item {
 	list-style-type: none;
 	position: relative;
 	margin-left: -1.5em;
 	padding-left: 0;
 }

 .task-list-item::before {
 	content: none;
 }

 .task-list-checkbox {
 	appearance: none;
 	-webkit-appearance: none;
 	width: 1em;
 	height: 1em;
 	border: 1px solid var(--vscode-checkbox-border, #6b6b6b);
 	border-radius: 3px;
 	background-color: var(--vscode-checkbox-background, transparent);
 	vertical-align: middle;
 	margin-right: 0.5em;
 	cursor: default;
 	position: relative;
 }

 .task-list-checkbox:checked {
 	background-color: var(--vscode-checkbox-selectBackground, #0078d4);
 	border-color: var(--vscode-checkbox-selectBorder, #0078d4);
 }

 .task-list-checkbox:checked::after {
 	content: "";
 	position: absolute;
 	left: 3px;
 	top: 0;
 	width: 4px;
 	height: 8px;
 	border: solid var(--vscode-checkbox-foreground, #fff);
 	border-width: 0 2px 2px 0;
 	transform: rotate(45deg);
 }

 /* Ensure task lists in prose context look good */
 .prose .task-list-item {
 	padding-left: 0.25em;
 }

 .prose ul:has(.task-list-item) {
 	padding-left: 1.5em;
 }

 /* Inline code styling for markdown preview */
 .prose code {
 	background-color: var(--vscode-textCodeBlock-background, rgba(255, 255, 255, 0.1));
 	color: var(--vscode-editor-foreground, inherit);
 	padding: 0.125em 0.375em;
 	border-radius: 3px;
 	font-family: var(--vscode-editor-font-family, monospace);
 	font-size: 0.875em;
 }

 /* Only apply nowrap to inline code, not code blocks */
 .prose p code,
 .prose li code,
 .prose td code,
 .prose th code {
 	white-space: nowrap;
 }

 .prose code::before,
 .prose code::after {
 	content: none;
 }

 /* Code block styling for markdown preview */
 .prose pre {
 	background-color: var(--vscode-textCodeBlock-background, rgba(0, 0, 0, 0.3));
 	border: 1px solid var(--vscode-input-border, #3c3c3c);
 	border-radius: 6px;
 	padding: 1rem;
 	overflow-x: auto;
 	margin: 0.75rem 0;
 }

 .prose pre code {
 	background-color: transparent;
 	padding: 0;
 	border-radius: 0;
 	font-size: 0.8125rem;
 	line-height: 1.5;
 	white-space: pre;
 	font-family: var(--vscode-editor-font-family, "Fira Code", "Consolas", monospace);
 }

 /* Prose spacing overrides - reduce excessive line height */
 .prose {
 	line-height: 1.6;
 }

 .prose p {
 	margin-top: 0.75em;
 	margin-bottom: 0.75em;
 	line-height: 1.6;
 }

 .prose ul,
 .prose ol {
 	margin-top: 0.5em;
 	margin-bottom: 0.5em;
 }

 .prose li {
 	margin-top: 0.25em;
 	margin-bottom: 0.25em;
 }

 .prose h1,
 .prose h2,
 .prose h3,
 .prose h4,
 .prose h5,
 .prose h6 {
 	margin-top: 1em;
 	margin-bottom: 0.5em;
 	line-height: 1.3;
 }

 .prose blockquote {
 	margin-top: 0.75em;
 	margin-bottom: 0.75em;
 	padding-left: 1em;
 	border-left: 3px solid var(--vscode-textBlockQuote-border, #007acc);
 }

 /* Mermaid diagram styling */
 .prose .mermaid {
 	background-color: var(--vscode-editor-background, #1e1e1e);
 	border-radius: 6px;
 	padding: 1rem;
 	margin: 0.75rem 0;
 	text-align: center;
 	overflow-x: auto;
 }

 /* Strong/bold text styling for markdown preview */
 .prose strong,
 .prose b {
 	font-weight: 700 !important;
 	color: inherit;
 }

 /* Emphasis/italic text styling for markdown preview */
 .prose em,
 .prose i {
 	font-style: italic !important;
 	color: inherit;
 }

 /* Ensure emphasis works in headings too */
 .prose h1 em,
 .prose h1 i,
 .prose h2 em,
 .prose h2 i,
 .prose h3 em,
 .prose h3 i,
 .prose h4 em,
 .prose h4 i,
 .prose h5 em,
 .prose h5 i,
 .prose h6 em,
 .prose h6 i {
