 }

 /* Ensure bold works in headings too */
 .prose h1 strong,
 .prose h1 b,
 .prose h2 strong,
 .prose h2 b,
 .prose h3 strong,
 .prose h3 b,
 .prose h4 strong,
 .prose h4 b,
